var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"꼭 당신이 가야만 하는 건가요?","JPN":"どうしてもあなたが行かないとダメなんですか？","ENG":"Do they really need you to go?","TWN":"非你不可嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"오랫동안 준비해온 일이야. 이제 와서 나 혼자 빠질 수는 없어.","JPN":"長い間準備してきたことだ。今更私だけ行かないわけにはいかない。","ENG":"We've been preparing for this for a long time. I can't back out now.","TWN":"這件事已經準備許久，我無法現在才說要退出。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"돌아오려면… 얼마나 걸릴까요?","JPN":"帰って来るまで……どのくらいかかるんでしょう？","ENG":"When... will you be back home?","TWN":"你這一趟去…多久才會回來？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"정확한 예정은 없지만, 그리 오래 걸리진 않을 거야.","JPN":"決まった日程はないが、そう長くはかからないはずだ。","ENG":"I don't know for sure, but it won't take long.","TWN":"還不確定，但應該不會太久。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"제발 무사해야 돼요.","JPN":"どうか無事でありますように。","ENG":"Please be safe.","TWN":"你一定要平安回來。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"당신도 부디 무사히 지내고 있어줘.","JPN":"あなたもどうか無事でいてくれ。","ENG":"You too, my love.","TWN":"這段時間你也要照顧好自己。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"잠깐만요.","JPN":"お待ちください。","ENG":"Wait!","TWN":"等等。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"…떠나기 전에 태어날 아이 이름이라도 지어주고 가요.","JPN":"……出発する前に、生まれてくる子の名前だけでも付けて行ってください。","ENG":"Before you leave... I want you to name our baby.","TWN":"離開之前……先替我肚子裡的寶寶取個名字吧。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"아직 남자인지 여자인지도 모르잖아.","JPN":"まだ男か女かもわからないじゃないか。","ENG":"We don't even know if it's a boy or a girl yet.","TWN":"都還不知道是男生還女生呢。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"기다려줘. 늦지 않게 돌아올 테니까.","JPN":"待っていておくれ。あまり遅くならないように頑張るから。","ENG":"Wait for me together. I'll be back as soon as I can.","TWN":"你跟孩子一起等我，我很快就回來。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"비비안.","JPN":"ビビアン。","ENG":"\\"Vivian\\".","TWN":"薇薇安。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"당신이 돌아오기 전에 아이가 태어난다면… 비비안이라고 불러줄게요.","JPN":"あなたが帰ってくる前にこの子が生まれたら……ビビアンと呼んであげようと思います。","ENG":"If I give birth before you return... I will name our baby Vivian.","TWN":"如果孩子在你回來之前出生的話…… 我會叫孩子薇薇安。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"또 혼자 그루터기에 앉아 사색하고 있었나?","JPN":"また一人で切り株に座って考え込んでいたのか？","ENG":"Daydreaming alone on that stump again?","TWN":"又一個人坐在樹上思考嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"일어나려던 참입니다, 장교님.","JPN":"もう行こうと思っていたところでした、将校。","ENG":"I was just about to get up, Officer Rashford.","TWN":"我正要起來呢，軍官。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…난 이곳 부대의 기술교관이다. 더 이상 그런 존칭은 하지 않아도 돼.","JPN":"……私はこの部隊の技術教官だ。もうそんな敬称はいらない。","ENG":"…I'm the Technical Instructor of your unit. You don't have to put \\"Officer\\" in front of my name anymore.","TWN":"……我是這個部隊的技術教官，已經不再使用那個稱號。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그래, 비비안.","JPN":"わかった、ビビアン。","ENG":"Very well, Vivian.","TWN":"好，薇薇安。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"너무 갔잖아! 교관이나 래시포드 씨라고 불러!","JPN":"呼び捨てか！　教官か、ラッシュフォードさんと呼べ！","ENG":"Don't you think that's going a little too far?! At least put a \\"Miss\\" in front or something!","TWN":"放尊重點！叫我教官或雷斯福特小姐！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…그리고 오늘은 새로운 신병들이 들어오는 날이다. 벌써 잊은 건 아니겠지?","JPN":"……そして今日は新兵が入ってくる日だ。忘れたわけではないだろうな。","ENG":"Also, today's the day the new recruits come in. You didn't forget, did you?","TWN":"……還有今天是新兵入伍的日子，你沒有忘吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그렇습니까?","JPN":"そうですか？","ENG":"Oh yeah?","TWN":"是嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"방금 전혀 몰랐다는 그 무성의한 대답. 그대로 엘라 부관에게 전해주지.","JPN":"今のそのまったく知らなかったかのような誠意のない返事。そのままエラ副官に伝えよう。","ENG":"That insincere response as if you didn't know... I'll make sure Miss Ella knows about it.","TWN":"剛才那個毫無誠意的回答，我會直接轉告給艾拉副隊長。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"부디 비밀로 해주시죠. 대신 이걸 돌려드리겠습니다.","JPN":"どうか内緒にしてください。その代わり、これをお返ししましょう。","ENG":"Please don't. In exchange, I'll give this back to you.","TWN":"請千萬保密，我把這個還給你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이건? 내 펜던트잖아?","JPN":"これは？　私のペンダントではないか。","ENG":"Hmm? That's my pendant...!","TWN":"這是？不是掛飾嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"많이 파손되어 있더군요. 기능을 복원하는 건 어렵지만, 외관은 고쳤습니다.","JPN":"かなり壊れていましたね。機能は復元できませんでしたが、外観は直しておきました。","ENG":"It was badly damaged, so I couldn't restore its functions. I restored it back it to its original form, however.","TWN":"壞得有點嚴重，雖然要恢復功能不容易，但起碼外觀已經修理完畢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…고맙군.","JPN":"……ありがとう。","ENG":"...I appreciate it.","TWN":"…謝謝。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그런데 이건 분명 내 방에 놓아뒀을 텐데, 어째서 귀관이 가지고 있는 거지?","JPN":"ところで、これは確か私の部屋に置いてあったはずだ。なぜ貴官が持っているんだ？","ENG":"But I'm sure I left this in my room. How come you have it with you?","TWN":"不過這個東西我明明放在我房裡，怎麼會在你的手裡呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이만 돌아가시죠. 다들 환영식으로 준비가 한창일 겁니다.","JPN":"もう戻りましょう。みんな歓迎会の準備をしてるはずです。","ENG":"Let's head back. Everyone should be busy preparing for the welcoming party.","TWN":"你先回去吧，大家應該都在忙著準備歡迎儀式。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"대장? …잠깐, 큐리안!","JPN":"隊長？　……待て、キュリアン！","ENG":"Captain? …Wait, Curian!","TWN":"隊長？ …等等，庫里安！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"너 뭐야! 내 방에 멋대로 들어왔던 거냐?!","JPN":"貴様、なんだ！　私の部屋に勝手に入ったのか！？","ENG":"Did you snoop through my stuff?!","TWN":"你幹嘛！誰准你擅自進我房間？！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"제가 아니라 허밋이 멋대로 물어왔을 뿐입니다.","JPN":"私ではなくて、ハーミットが勝手に持ってきただけです。","ENG":"It wasn't me, Hermit was the one who brought it to me.","TWN":"不是我，只是赫米特擅自進來的。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그 커다란 말이 대체 무슨 수로 내 방으로 들어오는데!?","JPN":"あの大きな馬がどうやって私の部屋に入るんだ！？","ENG":"Are you telling me a horse just walked into my room?","TWN":"那匹大馬到底用什麼辦法能進我房間？！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"문이 그 정도로 좁았습니까?","JPN":"扉がそれほど狭かったでしょうか？","ENG":"Through a door he can't even squeeze through?!","TWN":"房間門有那麼窄嗎?"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"뭐야, 너! 지금 내가 우스워? 왜 웃고 있는 건데!","JPN":"何だ、貴様！　からかっているのか？　なぜ笑っている！","ENG":"Answer me! What's so funny? Do you think I'm joking right now?!","TWN":"搞什麼，你！你現在是在耍我嗎？笑什麼笑！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"나한테 거짓말 안 할 거라며!","JPN":"私には嘘をつかないと言ったじゃないか！","ENG":"You said you weren't going to lie to me!","TWN":"你不是說你不會騙我的嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"큐리안!!!","JPN":"キュリアン！！！","ENG":"Curian!!!","TWN":"庫里安！！！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};